import { useEffect, useState } from "react";
import API from "../services/api";

function Teams() {
  const [teams, setTeams] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState({ name: "", country: "", coach: "", established: "" });
  const userInfo = JSON.parse(localStorage.getItem("userInfo"));

  useEffect(() => {
    fetchTeams();
  }, []);

  const fetchTeams = async () => {
    try {
      const { data } = await API.get("/teams");
      setTeams(data);
    } catch (err) {
      console.error("Failed to fetch teams");
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await API.post("/teams", formData);
      setShowForm(false);
      setFormData({ name: "", country: "", coach: "", established: "" });
      fetchTeams();
    } catch (err) {
      alert("Failed to add team");
    }
  };

  return (
    <div className="page">
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px' }}>
        <h2>Cricket Teams</h2>
        {userInfo && (
          <button onClick={() => setShowForm(!showForm)} className="auth-btn" style={{ width: 'auto', padding: '8px 15px' }}>
            {showForm ? "Cancel" : "Add New Team"}
          </button>
        )}
      </div>

      {showForm && (
        <div className="auth-card" style={{ margin: '0 0 20px 0', maxWidth: '100%' }}>
          <form onSubmit={handleSubmit} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: '15px' }}>
            <div className="input-group">
              <label>Team Name</label>
              <input type="text" value={formData.name} onChange={(e) => setFormData({...formData, name: e.target.value})} required />
            </div>
            <div className="input-group">
              <label>Country</label>
              <input type="text" value={formData.country} onChange={(e) => setFormData({...formData, country: e.target.value})} required />
            </div>
            <div className="input-group">
              <label>Coach</label>
              <input type="text" value={formData.coach} onChange={(e) => setFormData({...formData, coach: e.target.value})} />
            </div>
            <div className="input-group">
              <label>Established Year</label>
              <input type="number" value={formData.established} onChange={(e) => setFormData({...formData, established: e.target.value})} />
            </div>
            <button type="submit" className="auth-btn" style={{ gridColumn: 'span 1', alignSelf: 'flex-end', marginBottom: '16px' }}>Save Team</button>
          </form>
        </div>
      )}

      <div className="players-grid">
        {teams.map(team => (
          <div key={team._id} className="card team-card">
            <h4>{team.name}</h4>
            <p><strong>Country:</strong> {team.country}</p>
            <p><strong>Coach:</strong> {team.coach || 'N/A'}</p>
            <p><strong>Established:</strong> {team.established || 'N/A'}</p>
          </div>
        ))}
      </div>
    </div>
  );
}

export default Teams;
